mapper.select:
select id
from song
where id = #{id}

select id, title, details, album_id, null as action
from song
where id = #{id}

select
    s.id,
    s.title,
    case when (s.details->>'trackNumber' ~ '^\d+$') then (s.details->>'trackNumber')::int end track_number,
    s.album_id
from song s


        s.title ~* #{criteria.titleSearch}


        and exists (
            select *
            from transcription t
                inner join pub p on t.pub_id = p.id
                inner join pub_idx pi on p.pub_idx_id = pi.id
            where t.song_id = s.id
                and pi.name ~* #{criteria.pubNameSearch}
        )


        and exists (
            select *
            from album a
            where a.id = s.album_id
                and a.title ~* #{criteria.albumSearch}
        )


        and (
            exists (
                select *
                from song_artist sa
                    inner join artist a on sa.artist_id = a.id
                where sa.song_id = s.id
                    and a.name ~* #{criteria.artistSearch}
            )
            or exists (
                select *
                from album al
                    inner join artist a on al.primary_artist_id = a.id
                where al.id = s.album_id
                    and a.name ~* #{criteria.artistSearch}
            )
        )


        and (

                (
                    exists (
                        select *
                        from song_artist sa
                        where sa.song_id = s.id
                            and sa.artist_id = #{artistCriterion.id}

                            and exists (
                                select *
                                from jsonb_array_elements_text(sa.roles) as song_role(role)
                                where song_role.role in

                                    #{role}::text

                            )

                    )
                    or exists (
                        select *
                        from album al
                        where al.id = s.album_id
                            and al.primary_artist_id = #{artistCriterion.id}

                            and 'ALBUM_ARTIST' in

                                #{role}::text


                    )
                )

        )


        and s.album_id in

            #{albumId}



        and exists (
            select *
            from transcription t
            where t.song_id = s.id
                and t.pub_id in

                    #{pubId}

        )
